      /** Account Id Env */
      account_id_env?: string | null;
      /**
       * Max Tokens
       * @default 4096
       */
      max_tokens?: number;
      /** Context Window */
      context_window?: number | null;
      /**
       * Temperature
       * @default 0.7
       */
      temperature?: number;
      /**
       * Timeout
       * @default 600
       */
      timeout?: number;
      /** Cost Per 1K Input */
      cost_per_1k_input?: number | null;
      /** Cost Per 1K Output */
      cost_per_1k_output?: number | null;
      /**
       * Description
       * @default
       */
      description?: string;
      /** Tags */
      tags?: string[];
      /**
       * Created At
       * Format: date-time
       */
      created_at?: string;
      /**
       * Updated At
       * Format: date-time
       */
      updated_at?: string;
      /**
       * Protocol
       * @default litellm
       * @enum {string}
       */
      protocol?: "litellm" | "a2a" | "stt";
